SELECT COUNT(DISTINCT PB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB PP JOIN LATTES_PRODBIB PB ON PB.PK = PP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE WHERE (LOWER(COALESCE(S.CAMPUS_ATUAL, '')) LIKE '%cidade de goias%' OR LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'goi') AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%hist%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG, '')) LIKE '%hist%') AND PB.ANO GLOB '[0-9][0-9][0-9][0-9]' AND CAST(PB.ANO AS INTEGER) = 2024 AND LOWER(COALESCE(PB.TIPO, '')) LIKE '%capitulo de livro%'